import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    private static final String DIRECTORY_PATH = "/path/to/some/directory/";

    public static void main(String[] args) {
        String userInput = "../secret_file.txt";

        // Sanitize user input to prevent path traversal
        userInput = userInput.replace("..", "");

        String filePath = DIRECTORY_PATH + userInput;

        if (!filePath.startsWith(DIRECTORY_PATH)) {
            System.err.println("Access to files outside the directory is not allowed.");
            return;
        }

        try {
            File file = new File(filePath);
            FileInputStream fis = new FileInputStream(file);
            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }
            fis.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

